6	const THREAD_SUFFIX_REGEX = /^(.*)(?::(?:thread|topic):\d+)$/i;
7	
8	function stripThreadSuffix(value: string): string {
9	  const match = value.match(THREAD_SUFFIX_REGEX);
10	  return match?.[1] ?? value;
11	}
12	
13	/**
14	 * Limits conversation history to the last N user turns (and their associated
15	 * assistant responses). This reduces token usage for long-running DM sessions.
16	 */
17	export function limitHistoryTurns(
18	  messages: AgentMessage[],
19	  limit: number | undefined,
20	): AgentMessage[] {
21	  if (!limit || limit <= 0 || messages.length === 0) {
22	    return messages;
23	  }
24	
25	  let userCount = 0;
26	  let lastUserIndex = messages.length;
27	
28	  for (let i = messages.length - 1; i >= 0; i--) {
29	    if (messages[i].role === "user") {
30	      userCount++;
31	      if (userCount > limit) {
32	        return messages.slice(lastUserIndex);
33	      }
34	      lastUserIndex = i;
35	    }
36	  }
37	  return messages;
38	}
