40	/**
41	 * Extract provider + user ID from a session key and look up dmHistoryLimit.
42	 * Supports per-DM overrides and provider defaults.
43	 * For channel/group sessions, uses historyLimit from provider config.
44	 */
45	export function getHistoryLimitFromSessionKey(
46	  sessionKey: string | undefined,
47	  config: OpenClawConfig | undefined,
48	): number | undefined {
49	  if (!sessionKey || !config) {
50	    return undefined;
51	  }
52	
53	  const parts = sessionKey.split(":").filter(Boolean);
54	  const providerParts = parts.length >= 3 && parts[0] === "agent" ? parts.slice(2) : parts;
55	
56	  const provider = normalizeProviderId(providerParts[0] ?? "");
57	  if (!provider) {
58	    return undefined;
59	  }
60	
61	  const kind = normalizeOptionalLowercaseString(providerParts[1]);
62	  const userIdRaw = providerParts.slice(2).join(":");
63	  const userId = stripThreadSuffix(userIdRaw);
64	
65	  const resolveProviderConfig = (
66	    cfg: OpenClawConfig | undefined,
67	    providerId: string,
68	  ):
69	    | {
70	        historyLimit?: number;
71	        dmHistoryLimit?: number;
72	        dms?: Record<string, { historyLimit?: number }>;
73	      }
74	    | undefined => {
75	    const channels = cfg?.channels;
76	    if (!channels || typeof channels !== "object") {
77	      return undefined;
78	    }
79	    for (const [configuredProviderId, value] of Object.entries(
80	      channels as Record<string, unknown>,
81	    )) {
82	      if (normalizeProviderId(configuredProviderId) !== providerId) {
83	        continue;
84	      }
85	      if (!value || typeof value !== "object" || Array.isArray(value)) {
86	        return undefined;
87	      }
88	      return value as {
89	        historyLimit?: number;
90	        dmHistoryLimit?: number;
91	        dms?: Record<string, { historyLimit?: number }>;
92	      };
93	    }
94	    return undefined;
95	  };
96	
97	  const providerConfig = resolveProviderConfig(config, provider);
98	  if (!providerConfig) {
99	    return undefined;
100	  }
101	
102	  // For DM sessions: per-DM override -> dmHistoryLimit.
103	  // Accept both "direct" (new) and "dm" (legacy) for backward compat.
104	  if (kind === "dm" || kind === "direct") {
105	    if (userId && providerConfig.dms?.[userId]?.historyLimit !== undefined) {
106	      return providerConfig.dms[userId].historyLimit;
107	    }
108	    return providerConfig.dmHistoryLimit;
109	  }
110	
111	  // For channel/group sessions: use historyLimit from provider config
112	  // This prevents context overflow in long-running channel sessions
113	  if (kind === "channel" || kind === "group") {
114	    return providerConfig.historyLimit;
115	  }
116	
117	  return undefined;
118	}
119	
120	/**
121	 * @deprecated Use getHistoryLimitFromSessionKey instead.
122	 * Alias for backward compatibility.
123	 */
124	export const getDmHistoryLimitFromSessionKey = getHistoryLimitFromSessionKey;
