1	import { normalizeLowercaseStringOrEmpty } from "../../shared/string-coerce.js";
2	import { resolveAnthropicCacheRetentionFamily } from "./anthropic-family-cache-semantics.js";
3	
4	type CacheRetention = "none" | "short" | "long";
5	
6	export function isGooglePromptCacheEligible(params: {
7	  modelApi?: string;
8	  modelId?: string;
9	}): boolean {
10	  if (params.modelApi !== "google-generative-ai") {
11	    return false;
12	  }
13	  const normalizedModelId = normalizeLowercaseStringOrEmpty(params.modelId);
14	  return normalizedModelId.startsWith("gemini-2.5") || normalizedModelId.startsWith("gemini-3");
15	}
16	
17	export function resolveCacheRetention(
18	  extraParams: Record<string, unknown> | undefined,
19	  provider: string,
20	  modelApi?: string,
21	  modelId?: string,
22	): CacheRetention | undefined {
23	  const hasExplicitCacheConfig =
24	    extraParams?.cacheRetention !== undefined || extraParams?.cacheControlTtl !== undefined;
25	  const family = resolveAnthropicCacheRetentionFamily({
26	    provider,
27	    modelApi,
28	    modelId,
29	    hasExplicitCacheConfig,
30	  });
31	  const googleEligible = isGooglePromptCacheEligible({ modelApi, modelId });
32	
33	  if (!family && !googleEligible) {
34	    return undefined;
35	  }
36	
37	  const newVal = extraParams?.cacheRetention;
38	  if (newVal === "none" || newVal === "short" || newVal === "long") {
39	    return newVal;
40	  }
41	
42	  const legacy = extraParams?.cacheControlTtl;
43	  if (legacy === "5m") {
44	    return "short";
45	  }
46	  if (legacy === "1h") {
47	    return "long";
48	  }
49	
50	  return family === "anthropic-direct" ? "short" : undefined;
51	}
