235	function convertAnthropicMessages(
236	  messages: Context["messages"],
237	  model: AnthropicTransportModel,
238	  isOAuthToken: boolean,
239	) {
240	  const params: Array<Record<string, unknown>> = [];
241	  const transformedMessages = transformTransportMessages(messages, model, normalizeToolCallId);
242	  for (let i = 0; i < transformedMessages.length; i += 1) {
243	    const msg = transformedMessages[i];
244	    if (msg.role === "user") {
245	      if (typeof msg.content === "string") {
246	        if (msg.content.trim().length > 0) {
247	          params.push({
248	            role: "user",
249	            content: sanitizeTransportPayloadText(msg.content),
250	          });
251	        }
252	        continue;
253	      }
254	      const blocks: Array<
255	        | { type: "text"; text: string }
256	        | {
257	            type: "image";
258	            source: { type: "base64"; media_type: string; data: string };
259	          }
260	      > = msg.content.map((item) =>
261	        item.type === "text"
262	          ? {
263	              type: "text",
264	              text: sanitizeTransportPayloadText(item.text),
265	            }
266	          : {
267	              type: "image",
268	              source: {
269	                type: "base64",
270	                media_type: item.mimeType,
271	                data: item.data,
272	              },
273	            },
274	      );
275	      let filteredBlocks = model.input.includes("image")
276	        ? blocks
277	        : blocks.filter((block) => block.type !== "image");
278	      filteredBlocks = filteredBlocks.filter(
279	        (block) => block.type !== "text" || block.text.trim().length > 0,
280	      );
281	      if (filteredBlocks.length === 0) {
282	        continue;
283	      }
284	      params.push({
285	        role: "user",
286	        content: filteredBlocks,
287	      });
288	      continue;
289	    }
290	    if (msg.role === "assistant") {
291	      const blocks: Array<Record<string, unknown>> = [];
292	      for (const block of msg.content) {
293	        if (block.type === "text") {
294	          if (block.text.trim().length > 0) {
295	            blocks.push({
296	              type: "text",
297	              text: sanitizeTransportPayloadText(block.text),
298	            });
299	          }
300	          continue;
301	        }
302	        if (block.type === "thinking") {
303	          if (block.redacted) {
304	            blocks.push({
305	              type: "redacted_thinking",
306	              data: block.thinkingSignature,
307	            });
308	            continue;
309	          }
310	          if (block.thinking.trim().length === 0) {
311	            continue;
312	          }
313	          if (!block.thinkingSignature || block.thinkingSignature.trim().length === 0) {
314	            blocks.push({
315	              type: "text",
316	              text: sanitizeTransportPayloadText(block.thinking),
317	            });
318	          } else {
319	            blocks.push({
320	              type: "thinking",
321	              thinking: sanitizeTransportPayloadText(block.thinking),
322	              signature: block.thinkingSignature,
323	            });
324	          }
325	          continue;
326	        }
327	        if (block.type === "toolCall") {
328	          blocks.push({
329	            type: "tool_use",
330	            id: block.id,
331	            name: isOAuthToken ? toClaudeCodeName(block.name) : block.name,
332	            input: coerceTransportToolCallArguments(block.arguments),
333	          });
334	        }
335	      }
336	      if (blocks.length > 0) {
337	        params.push({
338	          role: "assistant",
339	          content: blocks,
340	        });
341	      }
342	      continue;
343	    }
344	    if (msg.role === "toolResult") {
345	      const toolResult = msg;
346	      const toolResults: Array<Record<string, unknown>> = [
347	        {
348	          type: "tool_result",
349	          tool_use_id: toolResult.toolCallId,
350	          content: convertContentBlocks(toolResult.content),
351	          is_error: toolResult.isError,
352	        },
353	      ];
354	      let j = i + 1;
355	      while (j < transformedMessages.length && transformedMessages[j].role === "toolResult") {
356	        const nextMsg = transformedMessages[j] as Extract<
357	          Context["messages"][number],
358	          { role: "toolResult" }
359	        >;
360	        toolResults.push({
361	          type: "tool_result",
362	          tool_use_id: nextMsg.toolCallId,
363	          content: convertContentBlocks(nextMsg.content),
364	          is_error: nextMsg.isError,
365	        });
366	        j += 1;
367	      }
368	      i = j - 1;
369	      params.push({
370	        role: "user",
371	        content: toolResults,
372	      });
373	    }
374	  }
375	  return params;
376	}
