496	function buildAnthropicParams(
497	  model: AnthropicTransportModel,
498	  context: Context,
499	  isOAuthToken: boolean,
500	  options: AnthropicTransportOptions | undefined,
501	) {
502	  const maxTokens = resolveAnthropicMessagesMaxTokens({
503	    modelMaxTokens: model.maxTokens,
504	    requestedMaxTokens: options?.maxTokens,
505	  });
506	  if (maxTokens === undefined) {
507	    throw new Error(
508	      `Anthropic Messages transport requires a positive maxTokens value for ${model.provider}/${model.id}`,
509	    );
510	  }
511	  const payloadPolicy = resolveAnthropicPayloadPolicy({
512	    provider: model.provider,
513	    api: model.api,
514	    baseUrl: model.baseUrl,
515	    cacheRetention: options?.cacheRetention,
516	    enableCacheControl: true,
517	  });
518	  const params: Record<string, unknown> = {
519	    model: model.id,
520	    messages: convertAnthropicMessages(context.messages, model, isOAuthToken),
521	    max_tokens: maxTokens,
522	    stream: true,
523	  };
524	  if (isOAuthToken) {
525	    params.system = [
526	      {
527	        type: "text",
528	        text: "You are Claude Code, Anthropic's official CLI for Claude.",
529	      },
530	      ...(context.systemPrompt
531	        ? [
532	            {
533	              type: "text",
534	              text: sanitizeTransportPayloadText(context.systemPrompt),
535	            },
536	          ]
537	        : []),
538	    ];
539	  } else if (context.systemPrompt) {
540	    params.system = [
541	      {
542	        type: "text",
543	        text: sanitizeTransportPayloadText(context.systemPrompt),
544	      },
545	    ];
546	  }
547	  if (options?.temperature !== undefined && !options.thinkingEnabled) {
548	    params.temperature = options.temperature;
549	  }
550	  if (context.tools) {
551	    params.tools = convertAnthropicTools(context.tools, isOAuthToken);
552	  }
553	  if (model.reasoning) {
554	    if (options?.thinkingEnabled) {
555	      if (supportsAdaptiveThinking(model.id)) {
556	        params.thinking = { type: "adaptive" };
557	        if (options.effort) {
558	          params.output_config = { effort: options.effort };
559	        }
560	      } else {
561	        params.thinking = {
562	          type: "enabled",
563	          budget_tokens: options.thinkingBudgetTokens || 1024,
564	        };
565	      }
566	    } else if (options?.thinkingEnabled === false) {
567	      params.thinking = { type: "disabled" };
568	    }
569	  }
570	  if (options?.metadata && typeof options.metadata.user_id === "string") {
571	    params.metadata = { user_id: options.metadata.user_id };
572	  }
573	  if (options?.toolChoice) {
574	    params.tool_choice =
575	      typeof options.toolChoice === "string" ? { type: options.toolChoice } : options.toolChoice;
576	  }
577	  applyAnthropicPayloadPolicyToParams(params, payloadPolicy);
578	  return params;
579	}
