581	function resolveAnthropicTransportOptions(
582	  model: AnthropicTransportModel,
583	  options: AnthropicTransportOptions | undefined,
584	  apiKey: string,
585	): AnthropicTransportOptions {
586	  const baseMaxTokens = resolveAnthropicMessagesMaxTokens({
587	    modelMaxTokens: model.maxTokens,
588	    requestedMaxTokens: options?.maxTokens,
589	  });
590	  if (baseMaxTokens === undefined) {
591	    throw new Error(
592	      `Anthropic Messages transport requires a positive maxTokens value for ${model.provider}/${model.id}`,
593	    );
594	  }
595	  const reasoningModelMaxTokens =
596	    resolvePositiveAnthropicMaxTokens(model.maxTokens) ?? baseMaxTokens;
597	  const resolved: AnthropicTransportOptions = {
598	    temperature: options?.temperature,
599	    maxTokens: baseMaxTokens,
600	    signal: options?.signal,
601	    apiKey,
602	    cacheRetention: options?.cacheRetention,
603	    sessionId: options?.sessionId,
604	    headers: options?.headers,
605	    onPayload: options?.onPayload,
606	    maxRetryDelayMs: options?.maxRetryDelayMs,
607	    metadata: options?.metadata,
608	    interleavedThinking: options?.interleavedThinking,
609	    toolChoice: options?.toolChoice,
610	    thinkingBudgets: options?.thinkingBudgets,
611	    reasoning: options?.reasoning,
612	  };
613	  if (!options?.reasoning) {
614	    resolved.thinkingEnabled = false;
615	    return resolved;
616	  }
617	  if (supportsAdaptiveThinking(model.id)) {
618	    resolved.thinkingEnabled = true;
619	    resolved.effort = mapThinkingLevelToEffort(options.reasoning, model.id);
620	    return resolved;
621	  }
622	  const adjusted = adjustMaxTokensForThinking({
623	    baseMaxTokens,
624	    modelMaxTokens: reasoningModelMaxTokens,
625	    reasoningLevel: options.reasoning,
626	    customBudgets: options.thinkingBudgets,
627	  });
628	  resolved.maxTokens = adjusted.maxTokens;
629	  resolved.thinkingEnabled = true;
630	  resolved.thinkingBudgetTokens = adjusted.thinkingBudget;
631	  return resolved;
632	}
