634	export function createAnthropicMessagesTransportStreamFn(): StreamFn {
635	  return (rawModel, context, rawOptions) => {
636	    const model = rawModel as AnthropicTransportModel;
637	    const options = rawOptions as AnthropicTransportOptions | undefined;
638	    const { eventStream, stream } = createWritableTransportEventStream();
639	    void (async () => {
640	      const output: MutableAssistantOutput = {
641	        role: "assistant",
642	        content: [],
643	        api: "anthropic-messages",
644	        provider: model.provider,
645	        model: model.id,
646	        usage: createEmptyTransportUsage(),
647	        stopReason: "stop",
648	        timestamp: Date.now(),
649	      };
650	      try {
651	        const apiKey = options?.apiKey ?? getEnvApiKey(model.provider) ?? "";
652	        if (!apiKey) {
653	          throw new Error(`No API key for provider: ${model.provider}`);
654	        }
655	        const transportOptions = resolveAnthropicTransportOptions(model, options, apiKey);
656	        const { client, isOAuthToken } = createAnthropicTransportClient({
657	          model,
658	          context,
659	          apiKey,
660	          options: transportOptions,
661	        });
662	        let params = buildAnthropicParams(model, context, isOAuthToken, transportOptions);
663	        const nextParams = await transportOptions.onPayload?.(params, model);
664	        if (nextParams !== undefined) {
665	          params = nextParams as Record<string, unknown>;
666	        }
667	        const anthropicStream = client.messages.stream(
668	          { ...params, stream: true } as never,
669	          transportOptions.signal ? { signal: transportOptions.signal } : undefined,
670	        ) as AsyncIterable<Record<string, unknown>>;
671	        stream.push({ type: "start", partial: output as never });
672	        const blocks = output.content;
673	        for await (const event of anthropicStream) {
674	          if (event.type === "message_start") {
675	            const message = event.message as
676	              | { id?: string; usage?: Record<string, unknown> }
677	              | undefined;
678	            const usage = message?.usage ?? {};
679	            output.responseId = typeof message?.id === "string" ? message.id : undefined;
680	            output.usage.input = typeof usage.input_tokens === "number" ? usage.input_tokens : 0;
681	            output.usage.output = typeof usage.output_tokens === "number" ? usage.output_tokens : 0;
682	            output.usage.cacheRead =
683	              typeof usage.cache_read_input_tokens === "number" ? usage.cache_read_input_tokens : 0;
684	            output.usage.cacheWrite =
685	              typeof usage.cache_creation_input_tokens === "number"
686	                ? usage.cache_creation_input_tokens
687	                : 0;
688	            output.usage.totalTokens =
689	              output.usage.input +
690	              output.usage.output +
691	              output.usage.cacheRead +
692	              output.usage.cacheWrite;
693	            calculateCost(model, output.usage);
694	            continue;
695	          }
696	          if (event.type === "content_block_start") {
697	            const contentBlock = event.content_block as Record<string, unknown> | undefined;
698	            const index = typeof event.index === "number" ? event.index : -1;
699	            if (contentBlock?.type === "text") {
700	              const block: TransportContentBlock = { type: "text", text: "", index };
701	              output.content.push(block);
702	              stream.push({
703	                type: "text_start",
704	                contentIndex: output.content.length - 1,
705	                partial: output as never,
706	              });
707	              continue;
708	            }
709	            if (contentBlock?.type === "thinking") {
710	              const block: TransportContentBlock = {
711	                type: "thinking",
712	                thinking: "",
713	                thinkingSignature: "",
714	                index,
715	              };
716	              output.content.push(block);
717	              stream.push({
718	                type: "thinking_start",
719	                contentIndex: output.content.length - 1,
720	                partial: output as never,
721	              });
722	              continue;
723	            }
724	            if (contentBlock?.type === "redacted_thinking") {
725	              const block: TransportContentBlock = {
726	                type: "thinking",
727	                thinking: "[Reasoning redacted]",
728	                thinkingSignature: typeof contentBlock.data === "string" ? contentBlock.data : "",
729	                redacted: true,
730	                index,
731	              };
732	              output.content.push(block);
733	              stream.push({
734	                type: "thinking_start",
735	                contentIndex: output.content.length - 1,
736	                partial: output as never,
737	              });
738	              continue;
739	            }
740	            if (contentBlock?.type === "tool_use") {
741	              const block: TransportContentBlock = {
742	                type: "toolCall",
743	                id: typeof contentBlock.id === "string" ? contentBlock.id : "",
744	                name:
745	                  typeof contentBlock.name === "string"
746	                    ? isOAuthToken
747	                      ? fromClaudeCodeName(contentBlock.name, context.tools)
748	                      : contentBlock.name
749	                    : "",
750	                arguments:
751	                  contentBlock.input && typeof contentBlock.input === "object"
752	                    ? (contentBlock.input as Record<string, unknown>)
753	                    : {},
754	                partialJson: "",
755	                index,
756	              };
757	              output.content.push(block);
758	              stream.push({
759	                type: "toolcall_start",
760	                contentIndex: output.content.length - 1,
761	                partial: output as never,
762	              });
763	            }
764	            continue;
765	          }
766	          if (event.type === "content_block_delta") {
767	            const index = blocks.findIndex((block) => block.index === event.index);
768	            const block = blocks[index];
769	            const delta = event.delta as Record<string, unknown> | undefined;
770	            if (
771	              block?.type === "text" &&
772	              delta?.type === "text_delta" &&
773	              typeof delta.text === "string"
774	            ) {
775	              block.text += delta.text;
776	              stream.push({
777	                type: "text_delta",
778	                contentIndex: index,
779	                delta: delta.text,
780	                partial: output as never,
781	              });
782	              continue;
783	            }
784	            if (
785	              block?.type === "thinking" &&
786	              delta?.type === "thinking_delta" &&
787	              typeof delta.thinking === "string"
788	            ) {
789	              block.thinking += delta.thinking;
790	              stream.push({
791	                type: "thinking_delta",
792	                contentIndex: index,
793	                delta: delta.thinking,
794	                partial: output as never,
795	              });
796	              continue;
797	            }
798	            if (
799	              block?.type === "toolCall" &&
800	              delta?.type === "input_json_delta" &&
801	              typeof delta.partial_json === "string"
802	            ) {
803	              block.partialJson += delta.partial_json;
804	              block.arguments = parseStreamingJson(block.partialJson);
805	              stream.push({
806	                type: "toolcall_delta",
807	                contentIndex: index,
808	                delta: delta.partial_json,
809	                partial: output as never,
810	              });
811	              continue;
812	            }
813	            if (
814	              block?.type === "thinking" &&
815	              delta?.type === "signature_delta" &&
816	              typeof delta.signature === "string"
817	            ) {
818	              block.thinkingSignature = `${block.thinkingSignature ?? ""}${delta.signature}`;
819	            }
820	            continue;
821	          }
822	          if (event.type === "content_block_stop") {
823	            const index = blocks.findIndex((block) => block.index === event.index);
824	            const block = blocks[index];
825	            if (!block) {
826	              continue;
827	            }
828	            delete block.index;
829	            if (block.type === "text") {
830	              stream.push({
831	                type: "text_end",
832	                contentIndex: index,
833	                content: block.text,
834	                partial: output as never,
835	              });
836	              continue;
837	            }
838	            if (block.type === "thinking") {
839	              stream.push({
840	                type: "thinking_end",
841	                contentIndex: index,
842	                content: block.thinking,
843	                partial: output as never,
844	              });
845	              continue;
846	            }
847	            if (block.type === "toolCall") {
848	              if (typeof block.partialJson === "string" && block.partialJson.length > 0) {
849	                block.arguments = parseStreamingJson(block.partialJson);
850	              }
851	              delete block.partialJson;
852	              stream.push({
853	                type: "toolcall_end",
854	                contentIndex: index,
855	                toolCall: block as never,
856	                partial: output as never,
857	              });
858	            }
859	            continue;
860	          }
861	          if (event.type === "message_delta") {
862	            const delta = event.delta as { stop_reason?: string } | undefined;
863	            const usage = event.usage as Record<string, unknown> | undefined;
864	            if (delta?.stop_reason) {
865	              output.stopReason = mapStopReason(delta.stop_reason);
866	            }
867	            if (typeof usage?.input_tokens === "number") {
868	              output.usage.input = usage.input_tokens;
869	            }
870	            if (typeof usage?.output_tokens === "number") {
871	              output.usage.output = usage.output_tokens;
872	            }
873	            if (typeof usage?.cache_read_input_tokens === "number") {
874	              output.usage.cacheRead = usage.cache_read_input_tokens;
875	            }
876	            if (typeof usage?.cache_creation_input_tokens === "number") {
877	              output.usage.cacheWrite = usage.cache_creation_input_tokens;
878	            }
879	            output.usage.totalTokens =
880	              output.usage.input +
881	              output.usage.output +
882	              output.usage.cacheRead +
883	              output.usage.cacheWrite;
884	            calculateCost(model, output.usage);
885	          }
886	        }
887	        finalizeTransportStream({ stream, output, signal: transportOptions.signal });
888	      } catch (error) {
889	        failTransportStream({
890	          stream,
891	          output,
892	          signal: options?.signal,
893	          error,
894	          cleanup: () => {
895	            for (const block of output.content) {
896	              delete block.index;
897	            }
898	          },
899	        });
900	      }
901	    })();
902	    return eventStream as ReturnType<StreamFn>;
903	  };
904	}
