43	function promptAgent(
44	  agent: AcpGatewayAgent,
45	  sessionId = DEFAULT_SESSION_ID,
46	  text = DEFAULT_PROMPT_TEXT,
47	) {
48	  return agent.prompt({
49	    sessionId,
50	    prompt: [{ type: "text", text }],
51	    _meta: {},
52	  } as unknown as PromptRequest);
53	}
