55	function observeSettlement(promise: ReturnType<AcpGatewayAgent["prompt"]>) {
56	  const settleSpy = vi.fn();
57	  void promise.then(
58	    (value) => settleSpy({ kind: "resolve", value }),
59	    (error) => settleSpy({ kind: "reject", error }),
60	  );
61	  return settleSpy;
62	}
